        // The request only included tag.category and tag.name, the composite foreign key. The response includes the whole object.
        "category": "belt",
        "name": "balancer",
        "ordinal": 1,
        // It was created a year earlier than the Blueprint.
        "systemFrom": "2000-01-01T00:00:00Z",
        "systemTo": null
      }
    }
  ]
